sql:
SELECT AVG(average_income) AS avg_income
FROM industries
WHERE unemployment_rate < (SELECT AVG(unemployment_rate) FROM industries);

SELECT workclass_name, AVG(median_income) AS average_median_income 
FROM workclasses
GROUP BY workclass_name;

SELECT workclass_name, median_income AS average_income
FROM workclasses
WHERE median_income > 40000;

SELECT occupation_name
FROM occupations
WHERE median_income > (SELECT AVG(average_income) FROM industries);

external_knowledge:
- "Top 3" refers to the highest ranks based on average median income;
- "Education level" is identified by the `education_name` column;
- "Workclass" is identified by the `workclass_name` column;
- The average median income is calculated for each combination of education and workclass.

sql:
SELECT gender_name, average_income
FROM genders
ORDER BY average_income DESC;

SELECT occupation_name
FROM occupations
WHERE median_income > (SELECT AVG(average_income) FROM industries);

